function useCountdown(hh, mm) {
  const [remaining, setRemaining] = useState("");
  useEffect(() => {
    if (hh == null || mm == null) return;
    const tick = () => {
      const now = new Date();
      const target = new Date();
      target.setHours(hh, mm, 0, 0);
      if (target < now) target.setDate(target.getDate() + 1);
      const diff = target - now;
      const h = String(Math.floor(diff / 3600000)).padStart(2, "0");
      const m = String(Math.floor((diff % 3600000) / 60000)).padStart(2, "0");
      const s = String(Math.floor((diff % 60000) / 1000)).padStart(2, "0");
      setRemaining(`${h}:${m}:${s}`);
    };
    tick();
    const id = setInterval(tick, 1000);
    return () => clearInterval(id);
  }, [hh, mm]);
  return remaining;
}

// قناة محتوى متزامنة مع قاعدة بيانات الهيئة (Firebase) — تُستخدم لكل قسم
// قابل للتعديل من لوحة التحكم. تحمّل القيمة المحفوظة، وإن لم توجد بعد
// تزرع القيمة الافتراضية أول مرة حتى يبدأ منها الأدمن بالتعديل.
// هوك خاص بمفاتيح الجنان: الكتاب الأساسي مدمج مع التطبيق (سريع ويعمل بلا نت)،
// ولا يُرفع لقاعدة البيانات. الأدمن يضيف أقساماً إضافية فقط، وهذه الإضافات
// وحدها تُحفظ في قاعدة البيانات (خفيفة) وتُدمج فوق الكتاب الأساسي.
function useMafatih() {
  const [extras, setExtras] = useState({}); // { babId: [ {title, source, body}, ... ] }
  useEffect(() => {
    (async () => {
      try {
        const res = await storage.get("hayaa_mafatih_extras");
        if (res && res.value) setExtras(JSON.parse(res.value));
      } catch (e) { console.error("mafatih extras", e); }
    })();
  }, []);

  const merged = DEFAULT_MAFATIH.map((bab) => ({
    ...bab,
    sections: [...(bab.sections || []), ...((extras[bab.id]) || [])],
  }));

  // للأدمن: إضافة/حذف أقسام إضافية (لا تمسّ الكتاب الأساسي المدمج)
  const saveExtras = async (babId, sections) => {
    const updated = { ...extras, [babId]: sections };
    setExtras(updated);
    try { await storage.set("hayaa_mafatih_extras", JSON.stringify(updated)); } catch (e) { console.error(e); }
  };

  return [merged, extras, saveExtras];
}

function useSyncedContent(key, defaultValue) {
  const [data, setData] = useState(defaultValue);
  const [loaded, setLoaded] = useState(false);
  useEffect(() => {
    (async () => {
      try {
        const res = await storage.get(key);
        if (res && res.value) setData(JSON.parse(res.value));
        else await storage.set(key, JSON.stringify(defaultValue));
      } catch (e) { console.error(key, e); }
      setLoaded(true);
    })();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [key]);
  const save = async (newData) => {
    setData(newData);
    try { await storage.set(key, JSON.stringify(newData)); } catch (e) { console.error(e); }
  };
  return [data, save, loaded];
}

// مواقيت الصلاة والقبلة الحقيقية — تُحسب تلقائياً حسب موقع الزائر الفعلي
// عبر Aladhan API المجاني (بدون مفتاح API)، بدل الاعتماد على مدينة ثابتة.
// method=0 يعني اعتماد طريقة الحساب الجعفرية (الشيعة الإثنا عشرية) بدل
// الطرق السنية الافتراضية، و midnightMode=1 يحسب منتصف الليل الشرعي
// من الغروب إلى الفجر وفق الفقه الجعفري بدل الغروب إلى الشروق.
function usePrayerData() {
  const [state, setState] = useState({ status: "idle", timings: null, qibla: null, error: "" });

  useEffect(() => {
    if (!navigator.geolocation) { setState((s) => ({ ...s, status: "unsupported" })); return; }
    setState((s) => ({ ...s, status: "locating" }));
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        const { latitude, longitude } = pos.coords;
        try {
          const today = new Date();
          const dateStr = `${String(today.getDate()).padStart(2, "0")}-${String(today.getMonth() + 1).padStart(2, "0")}-${today.getFullYear()}`;
          const [timingsRes, qiblaRes] = await Promise.all([
            fetch(`https://api.aladhan.com/v1/timings/${dateStr}?latitude=${latitude}&longitude=${longitude}&method=0&school=0&midnightMode=1`).then((r) => r.json()),
            fetch(`https://api.aladhan.com/v1/qibla/${latitude}/${longitude}`).then((r) => r.json()),
          ]);
          setState({
            status: "ready",
            timings: timingsRes && timingsRes.data ? timingsRes.data.timings : null,
            qibla: qiblaRes && qiblaRes.data ? qiblaRes.data.direction : null,
            error: "",
          });
        } catch (e) {
          setState((s) => ({ ...s, status: "error", error: "تعذر جلب مواقيت الصلاة من الإنترنت." }));
        }
      },
      () => setState((s) => ({ ...s, status: "denied" })),
      { enableHighAccuracy: true, timeout: 12000 }
    );
  }, []);

  return state;
}

function parseTimeStr(t) {
  if (!t) return [null, null];
  const clean = t.split(" ")[0]; // يزيل أي منطقة زمنية إضافية ترجعها الـ API أحياناً
  const [h, m] = clean.split(":").map(Number);
  return [h, m];
}

const PRAYER_SEQUENCE = [["Fajr", "الفجر"], ["Dhuhr", "الظهر"], ["Asr", "العصر"], ["Maghrib", "المغرب"], ["Isha", "العشاء"]];

// يحدد الصلاة القادمة الوحيدة (بدل عرض عدادات منفصلة لكل صلاة) — يعيد فحص
// نفسه كل 30 ثانية عشان ينتقل تلقائياً للصلاة التالية بمجرد ما يدخل وقتها.
function useNextPrayer(timings) {
  const [next, setNext] = useState(null);
  useEffect(() => {
    if (!timings) { setNext(null); return; }
    const compute = () => {
      const now = new Date();
      let found = null;
      for (const [key, label] of PRAYER_SEQUENCE) {
        const [h, m] = parseTimeStr(timings[key]);
        if (h == null) continue;
        const t = new Date(); t.setHours(h, m, 0, 0);
        if (t > now) { found = { key, label, h, m }; break; }
      }
      if (!found) {
        const [h, m] = parseTimeStr(timings.Fajr);
        found = { key: "Fajr", label: "الفجر", h, m };
      }
      setNext(found);
    };
    compute();
    const id = setInterval(compute, 30000);
    return () => clearInterval(id);
  }, [timings]);
  return next;
}

