function PostsView({ posts, setPosts, isAdmin }) {
  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [saving, setSaving] = useState(false);

  const persist = async (arr) => { try { await storage.set("hayaa_posts", JSON.stringify(arr)); } catch (e) { console.error(e); } };

  const addPost = async () => {
    if (!title.trim() || !body.trim()) return;
    setSaving(true);
    const newPost = { id: Date.now().toString(), title: title.trim(), body: body.trim(), date: new Date().toLocaleDateString("ar-IQ", { day: "numeric", month: "long" }) };
    const arr = [newPost, ...posts];
    setPosts(arr); await persist(arr);
    setTitle(""); setBody(""); setSaving(false);
  };
  const removePost = async (id) => { const arr = posts.filter((p) => p.id !== id); setPosts(arr); await persist(arr); };

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow="بلاغ" title="منشورات الهيئة" icon={Megaphone} />
      {isAdmin && (
        <Card style={{ border: "1px solid #C6A15B55" }}>
          <div className="text-xs mb-3 flex items-center gap-2" style={{ color: "#C6A15B" }}><Lock size={13} /> لوحة نشر — إدارة الهيئة</div>
          <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="عنوان المنشور" className="w-full rounded-xl px-3 py-2 text-sm mb-2 outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <textarea value={body} onChange={(e) => setBody(e.target.value)} placeholder="نص المنشور..." className="w-full rounded-xl px-3 py-2 text-sm h-24 outline-none resize-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <button onClick={addPost} disabled={saving} className="mt-2 w-full py-2.5 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}><Send size={14} /> {saving ? "جاري النشر..." : "نشر"}</button>
        </Card>
      )}
      <div className="space-y-2">
        {posts.length === 0 && <Card><p className="text-xs" style={{ color: "#8FA396" }}>لا توجد منشورات حتى الآن.</p></Card>}
        {posts.map((p) => (
          <Card key={p.id}>
            <div className="flex items-center justify-between mb-1">
              <span className="text-sm font-semibold" style={{ color: "#F3EEDF" }}>{p.title}</span>
              <div className="flex items-center gap-2"><span className="text-[10px]" style={{ color: "#6E8377" }}>{p.date}</span>{isAdmin && <button onClick={() => removePost(p.id)}><Trash2 size={13} color="#E3866A" /></button>}</div>
            </div>
            <p className="text-xs leading-6" style={{ color: "#B7C4BB" }}>{p.body}</p>
          </Card>
        ))}
      </div>
    </div>
  );
}

function AdminGate() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async () => {
    setErr(""); setLoading(true);
    try {
      await signInWithEmailAndPassword(auth, email.trim(), password);
    } catch (e) {
      setErr("الإيميل أو كلمة السر غير صحيحة.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="pt-4 flex flex-col items-center gap-2">
      <div className="text-[11px]" style={{ color: "#5C6B60" }}>دخول إدارة الهيئة</div>
      <div className="w-full max-w-xs space-y-2">
        <input value={email} onChange={(e) => { setEmail(e.target.value); setErr(""); }} type="email" placeholder="الإيميل" className="w-full rounded-xl px-3 py-2 text-sm text-center outline-none" style={{ background: "#0F1913", border: "1px solid " + (err ? "#A6402F" : "#24382C"), color: "#F3EEDF" }} />
        <input value={password} onChange={(e) => { setPassword(e.target.value); setErr(""); }} type="password" placeholder="كلمة السر" className="w-full rounded-xl px-3 py-2 text-sm text-center outline-none" style={{ background: "#0F1913", border: "1px solid " + (err ? "#A6402F" : "#24382C"), color: "#F3EEDF" }} onKeyDown={(e) => e.key === "Enter" && handleLogin()} />
        <button onClick={handleLogin} disabled={loading} className="w-full px-4 py-2.5 rounded-xl text-sm" style={{ background: "#1F6B45", color: "#F3EEDF", fontWeight: 700 }}>{loading ? "جاري الدخول..." : "دخول"}</button>
      </div>
      {err && <div className="text-[11px]" style={{ color: "#E3866A" }}>{err}</div>}
    </div>
  );
}

