/* --------------------------------- حساب التقويم الهجري الحقيقي --------------------------------- */

// يحوّل أي تاريخ ميلادي إلى يوم/شهر/سنة هجري حقيقي عبر تقويم أم القرى
// المدمج بالمتصفح نفسه (بدون أي مكتبة خارجية).
function toHijriParts(date) {
  const fmt = new Intl.DateTimeFormat("en-u-ca-islamic-umalqura", { day: "numeric", month: "numeric", year: "numeric" });
  const obj = {};
  fmt.formatToParts(date).forEach((p) => { if (p.type !== "literal") obj[p.type] = parseInt(p.value, 10); });
  return { day: obj.day, month: obj.month, year: obj.year };
}

function addDays(date, n) {
  const d = new Date(date);
  d.setDate(d.getDate() + n);
  return d;
}

// يبني كل أيام الشهر الهجري الذي يقع فيه التاريخ المُعطى، بالاعتماد على أن
// كل يوم هجري يقابله يوم ميلادي واحد بالضبط (نفس عدد الأيام)، فنطرح رقم
// اليوم الهجري الحالي لنصل ليوم 1 من نفس الشهر، ثم نعدّ للأمام حتى يتغيّر الشهر.
function buildHijriMonth(anchorDate) {
  const anchor = toHijriParts(anchorDate);
  const monthStart = addDays(anchorDate, -(anchor.day - 1));
  const days = [];
  let cursor = monthStart;
  while (true) {
    const parts = toHijriParts(cursor);
    if (parts.month !== anchor.month || parts.year !== anchor.year) break;
    days.push({ date: cursor, hijriDay: parts.day, weekday: cursor.getDay() });
    cursor = addDays(cursor, 1);
    if (days.length > 30) break; // حماية من حلقة لا نهائية
  }
  return { monthStart, monthNumber: anchor.month, year: anchor.year, days };
}

function CalendarView({ occasions }) {
  const today = new Date();
  const [viewDate, setViewDate] = useState(today);
  const monthData = buildHijriMonth(viewDate);
  const monthName = HIJRI_MONTHS[monthData.monthNumber - 1];
  const todayHijri = toHijriParts(today);
  const isCurrentMonth = todayHijri.month === monthData.monthNumber && todayHijri.year === monthData.year;

  const goPrevMonth = () => setViewDate(addDays(monthData.monthStart, -1));
  const goNextMonth = () => setViewDate(addDays(monthData.days[monthData.days.length - 1].date, 1));

  const leadingBlanks = monthData.days.length ? monthData.days[0].weekday : 0;
  const grid = [...Array(leadingBlanks).fill(null), ...monthData.days];
  const weeks = [];
  for (let i = 0; i < grid.length; i += 7) weeks.push(grid.slice(i, i + 7));

  const eventDaysThisMonth = occasions.filter((o) => o.m === monthName);

  const [tab, setTab] = useState("month");
  const [convertInput, setConvertInput] = useState("");
  const [convertResult, setConvertResult] = useState(null);
  const convert = () => {
    if (!convertInput) return;
    const d = new Date(convertInput + "T12:00:00");
    const h = toHijriParts(d);
    setConvertResult(`${h.day} ${HIJRI_MONTHS[h.month - 1]} ${h.year} هـ`);
  };

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow={`${monthName} ${monthData.year} هـ`} title="التقويم الهجري" icon={CalendarDays} />
      <div className="flex gap-2">
        {[{ id: "month", label: "هذا الشهر" }, { id: "year", label: "مناسبات السنة" }].map((t) => (
          <button key={t.id} onClick={() => setTab(t.id)} className="flex-1 py-2.5 rounded-xl text-sm" style={{ background: tab === t.id ? "linear-gradient(135deg,#1F6B45,#0F3D28)" : "transparent", border: "1px solid " + (tab === t.id ? "#C6A15B" : "#24382C"), color: tab === t.id ? "#F3EEDF" : "#8FA396" }}>{t.label}</button>
        ))}
      </div>

      {tab === "month" ? (
        <>
          <Card>
            <div className="flex items-center justify-between mb-4">
              <button onClick={goNextMonth}><ChevronRight size={18} color="#8FA396" /></button>
              <span style={{ fontFamily: "'Cairo', sans-serif", fontWeight: 800, color: "#F3EEDF" }}>{monthName} {monthData.year}</span>
              <button onClick={goPrevMonth}><ChevronLeft size={18} color="#8FA396" /></button>
            </div>
            <div className="grid grid-cols-7 gap-1 text-center text-[11px] mb-2" style={{ color: "#8FA396" }}>{["أحد","اثن","ثلا","أرب","خمي","جمع","سبت"].map((d) => <div key={d}>{d}</div>)}</div>
            {weeks.map((w, wi) => (
              <div key={wi} className="grid grid-cols-7 gap-1 mb-1">
                {w.map((cell, di) => {
                  const isToday = isCurrentMonth && cell && cell.hijriDay === todayHijri.day;
                  const hasEvent = cell && eventDaysThisMonth.some((o) => o.d === cell.hijriDay);
                  return (
                    <div key={di} className="aspect-square flex items-center justify-center rounded-lg text-sm" style={{ background: isToday ? "#C6A15B" : "transparent", color: isToday ? "#0A1310" : hasEvent ? "#E3C078" : cell ? "#B7C4BB" : "transparent", fontWeight: isToday ? 700 : 400 }}>{cell ? cell.hijriDay : ""}</div>
                  );
                })}
              </div>
            ))}
          </Card>
          <Card>
            <div className="text-sm font-semibold mb-2" style={{ color: "#F3EEDF" }}>مناسبات الشهر</div>
            {eventDaysThisMonth.length === 0 && <p className="text-xs" style={{ color: "#6E8377" }}>لا توجد مناسبات مسجلة هذا الشهر.</p>}
            {eventDaysThisMonth.map((o, i) => (
              <div key={i} className="flex items-start gap-3 py-2" style={{ borderBottom: i < eventDaysThisMonth.length - 1 ? "1px solid #24382C" : "none" }}>
                <div className="text-xs px-2 py-1 rounded-md shrink-0" style={{ background: "#1F6B4533", color: "#8FD6A8" }}>{o.d}</div>
                <p className="text-xs leading-6" style={{ color: "#B7C4BB" }}>{o.t}</p>
              </div>
            ))}
          </Card>
          <Card>
            <div className="text-sm font-semibold mb-3" style={{ color: "#F3EEDF" }}>محول التاريخ (ميلادي ← هجري)</div>
            <div className="flex items-center gap-3">
              <input type="date" value={convertInput} onChange={(e) => setConvertInput(e.target.value)} className="flex-1 rounded-xl px-3 py-2 text-sm" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
              <button onClick={convert} className="px-4 py-2 rounded-xl text-sm" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}>تحويل</button>
            </div>
            {convertResult && <div className="mt-3 text-sm text-center" style={{ fontFamily: "'Cairo', sans-serif", fontWeight: 800, color: "#E3C078" }}>{convertResult}</div>}
          </Card>
        </>
      ) : (
        <div className="space-y-2">
          {HIJRI_MONTHS.map((month) => {
            const items = occasions.filter((o) => o.m === month);
            if (items.length === 0) return null;
            return (
              <Card key={month}>
                <div className="text-sm font-semibold mb-2" style={{ color: "#E3C078", fontFamily: "'Cairo', sans-serif", fontWeight: 800 }}>{month}</div>
                {items.map((o, i) => (
                  <div key={i} className="flex items-start gap-3 py-1.5">
                    <div className="text-[11px] px-2 py-0.5 rounded-md shrink-0" style={{ background: "#17261E", color: "#8FA396" }}>{o.d}</div>
                    <p className="text-xs leading-6" style={{ color: "#B7C4BB" }}>{o.t}</p>
                  </div>
                ))}
              </Card>
            );
          })}
        </div>
      )}
    </div>
  );
}

