const RECITERS = [
  { id: "ar.alafasy", name: "مشاري راشد العفاسي" },
  { id: "ar.abdulbasitmurattal", name: "عبد الباسط عبد الصمد" },
  { id: "ar.minshawi", name: "محمد صديق المنشاوي" },
  { id: "ar.husary", name: "محمود خليل الحصري" },
  { id: "ar.abdurrahmaansudais", name: "عبد الرحمن السديس" },
  { id: "ar.mahermuaiqly", name: "ماهر المعيقلي" },
  { id: "ar.hudhaify", name: "علي الحذيفي" },
  { id: "ar.shaatree", name: "أبو بكر الشاطري" },
];

function SurahReader({ surah, onBack }) {
  const [ayahs, setAyahs] = useState(null);
  const [error, setError] = useState("");
  const [playingIdx, setPlayingIdx] = useState(null);
  const [autoPlay, setAutoPlay] = useState(false);
  const [reciter, setReciter] = useState(RECITERS[0].id);
  const audioRef = useRef(null);

  useEffect(() => {
    setAyahs(null); setError(""); setPlayingIdx(null); setAutoPlay(false);
    fetch(`https://api.alquran.cloud/v1/surah/${surah.n}/editions/quran-uthmani,${reciter}`)
      .then((r) => r.json())
      .then((json) => {
        const [textEd, audioEd] = json.data;
        const combined = textEd.ayahs.map((a, i) => ({ n: a.numberInSurah, text: a.text, audio: audioEd.ayahs[i] ? audioEd.ayahs[i].audio : null }));
        setAyahs(combined);
      })
      .catch(() => setError("تعذر تحميل السورة، تأكد من اتصال الإنترنت."));
  }, [surah.n, reciter]);

  const playAyah = (idx) => {
    if (!ayahs || !ayahs[idx] || !ayahs[idx].audio) return;
    setPlayingIdx(idx);
    if (audioRef.current) { audioRef.current.src = ayahs[idx].audio; audioRef.current.play(); }
  };

  const handleEnded = () => {
    if (autoPlay && ayahs && playingIdx !== null && playingIdx + 1 < ayahs.length) {
      playAyah(playingIdx + 1);
    } else {
      setPlayingIdx(null);
    }
  };

  const playFullSurah = () => { setAutoPlay(true); playAyah(0); };
  const stopPlayback = () => { setAutoPlay(false); setPlayingIdx(null); if (audioRef.current) audioRef.current.pause(); };

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <div className="flex items-center gap-3">
        <button onClick={onBack} className="w-9 h-9 rounded-full flex items-center justify-center shrink-0" style={{ background: "#17261E" }}><ChevronRight size={16} color="#E3C078" /></button>
        <SectionTitle eyebrow={`${surah.verses} آية`} title={`سورة ${surah.name}`} icon={BookOpen} />
      </div>

      <audio ref={audioRef} onEnded={handleEnded} />

      {error && <Card><p className="text-xs" style={{ color: "#E3866A" }}>{error}</p></Card>}
      {!ayahs && !error && <Card><p className="text-xs" style={{ color: "#8FA396" }}>جاري تحميل نص السورة والتلاوة...</p></Card>}

      {ayahs && (
        <>
          <Card>
            <div className="text-xs font-semibold mb-2" style={{ color: "#C6A15B" }}>اختر القارئ</div>
            <select value={reciter} onChange={(e) => { stopPlayback(); setReciter(e.target.value); }} className="w-full rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }}>
              {RECITERS.map((r) => <option key={r.id} value={r.id}>{r.name}</option>)}
            </select>
          </Card>
          <div className="flex gap-2">
            {playingIdx === null ? (
              <button onClick={playFullSurah} className="flex-1 py-2.5 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}>تشغيل السورة كاملة ({RECITERS.find((r) => r.id === reciter).name})</button>
            ) : (
              <button onClick={stopPlayback} className="flex-1 py-2.5 rounded-xl text-sm" style={{ background: "#A6402F", color: "#F3EEDF", fontWeight: 700 }}>إيقاف التلاوة</button>
            )}
          </div>
          <Card>
            <div className="space-y-4" dir="rtl">
              {ayahs.map((a, i) => (
                <div key={a.n} dir="rtl" className="flex items-start gap-3 pb-4" style={{ borderBottom: i < ayahs.length - 1 ? "1px solid #17261E" : "none" }}>
                  <button onClick={() => { setAutoPlay(false); playAyah(i); }} className="w-8 h-8 rounded-full flex items-center justify-center shrink-0 mt-1" style={{ background: playingIdx === i ? "#C6A15B" : "#17261E" }}>
                    <Music2 size={13} color={playingIdx === i ? "#0A1310" : "#8FA396"} />
                  </button>
                  <p className="text-lg leading-[2.4] flex-1" style={{ fontFamily: "'Cairo', sans-serif", fontWeight: 800, color: playingIdx === i ? "#E3C078" : "#F3EEDF" }}>{a.text} <span className="text-sm" style={{ color: "#6E8377" }}>﴿{a.n}﴾</span></p>
                </div>
              ))}
            </div>
          </Card>
        </>
      )}
    </div>
  );
}

