function LecturesView() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [query, setQuery] = useState("");
  const [visibleCount, setVisibleCount] = useState(50);
  const [selected, setSelected] = useState(null);
  const sentinelRef = useRef(null);

  // نجيب كل حلقات القائمة دفعة تلو الأخرى بالخلفية (٥٠ كل مرة) حتى يشتغل
  // البحث فوراً على كل المحاضرات، بينما العرض على الشاشة يبقى تدريجياً.
  useEffect(() => {
    let cancelled = false;
    const fetchAll = async () => {
      let pageToken = "";
      let all = [];
      try {
        do {
          const url = `https://www.googleapis.com/youtube/v3/playlistItems?part=snippet&maxResults=50&playlistId=${YOUTUBE_PLAYLIST_ID}&key=${YOUTUBE_API_KEY}${pageToken ? `&pageToken=${pageToken}` : ""}`;
          const res = await fetch(url);
          const json = await res.json();
          if (json.error) { setError("تعذر تحميل المحاضرات — تأكد من إعدادات مفتاح YouTube."); return; }
          const items = (json.items || [])
            .filter((it) => it.snippet && it.snippet.resourceId && it.snippet.resourceId.videoId)
            .map((it) => ({
              id: it.snippet.resourceId.videoId,
              title: it.snippet.title,
              thumb: it.snippet.thumbnails && (it.snippet.thumbnails.medium || it.snippet.thumbnails.default).url,
            }));
          all = [...all, ...items];
          if (!cancelled) setVideos([...all]);
          pageToken = json.nextPageToken || "";
        } while (pageToken && !cancelled);
      } catch (e) {
        if (!cancelled) setError("تعذر الاتصال بيوتيوب، تأكد من اتصال الإنترنت.");
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    fetchAll();
    return () => { cancelled = true; };
  }, []);

  const filtered = query ? videos.filter((v) => v.title.toLowerCase().includes(query.toLowerCase())) : videos;
  const visible = filtered.slice(0, visibleCount);

  useEffect(() => {
    if (!sentinelRef.current) return;
    const obs = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting) setVisibleCount((c) => Math.min(c + 50, filtered.length));
    }, { rootMargin: "200px" });
    obs.observe(sentinelRef.current);
    return () => obs.disconnect();
  }, [filtered.length]);

  useEffect(() => { setVisibleCount(50); }, [query]);

  if (selected) return <VideoPlayer video={selected} onBack={() => setSelected(null)} />;

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      <SectionTitle eyebrow={videos.length ? `${videos.length} محاضرة` : "جاري التحميل"} title="محاضرات الشيخ أحمد الوائلي" icon={Video} />

      <div className="flex items-center gap-2 rounded-xl px-3 py-2" style={{ background: "#0F1913", border: "1px solid #24382C" }}>
        <Search size={16} color="#8FA396" />
        <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="ابحث بعنوان المحاضرة..." className="bg-transparent text-sm flex-1 outline-none" style={{ color: "#F3EEDF" }} />
      </div>

      {error && <Card><p className="text-xs" style={{ color: "#E3866A" }}>{error}</p></Card>}

      {videos.length === 0 && loading && (
        <div className="grid grid-cols-2 gap-3">
          {Array.from({ length: 6 }).map((_, i) => (
            <div key={i} className="rounded-2xl overflow-hidden" style={{ background: "#101B15", border: "1px solid #1C2B22" }}>
              <div className="aspect-video" style={{ background: "#17261E" }} />
              <div className="p-2.5"><div className="h-3 rounded" style={{ background: "#17261E", width: "80%" }} /></div>
            </div>
          ))}
        </div>
      )}

      {visible.length > 0 && (
        <>
          <div className="grid grid-cols-2 gap-3">
            {visible.map((v) => (
              <button key={v.id} onClick={() => setSelected(v)} className="rounded-2xl overflow-hidden text-right" style={{ background: "#101B15", border: "1px solid #1C2B22" }}>
                <div className="aspect-video relative overflow-hidden">
                  <img src={v.thumb} alt={v.title} className="w-full h-full object-cover" />
                  <div className="absolute inset-0 flex items-center justify-center" style={{ background: "#0A131066" }}>
                    <div className="w-9 h-9 rounded-full flex items-center justify-center" style={{ background: "#C6A15Bdd" }}><Video size={15} color="#0A1310" /></div>
                  </div>
                </div>
                <div className="p-2.5"><p className="text-[11px] leading-5 line-clamp-2" style={{ color: "#F3EEDF" }}>{v.title}</p></div>
              </button>
            ))}
          </div>
          {visible.length < filtered.length && <div ref={sentinelRef} className="text-center text-[11px] py-4" style={{ color: "#5C6B60" }}>جاري تحميل المزيد...</div>}
          {query && filtered.length === 0 && <p className="text-center text-xs py-6" style={{ color: "#6E8377" }}>ماكو نتائج لهذا البحث.</p>}
        </>
      )}
    </div>
  );
}


