/* --------------------------------- محررات المحتوى العامة --------------------------------- */

function TextFieldEditor({ label, value, onSave, multiline }) {
  const [val, setVal] = useState(value);
  const [saved, setSaved] = useState(false);
  useEffect(() => setVal(value), [value]);
  const Field = multiline ? "textarea" : "input";
  return (
    <Card>
      <div className="text-xs font-semibold mb-2" style={{ color: "#C6A15B" }}>{label}</div>
      <Field value={val} onChange={(e) => { setVal(e.target.value); setSaved(false); }} className={"w-full rounded-xl px-3 py-2 text-sm outline-none " + (multiline ? "h-24 resize-none" : "")} style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
      <button onClick={() => { onSave(val); setSaved(true); }} className="mt-2 px-4 py-2 rounded-xl text-sm" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}>حفظ</button>
      {saved && <span className="text-[11px] mr-2" style={{ color: "#8FD6A8" }}>تم الحفظ ✓</span>}
    </Card>
  );
}

function ListEditor({ label, items, onSave, placeholder }) {
  const [draft, setDraft] = useState("");
  const add = () => { if (!draft.trim()) return; onSave([...items, draft.trim()]); setDraft(""); };
  const remove = (i) => onSave(items.filter((_, idx) => idx !== i));
  return (
    <Card>
      <div className="text-xs font-semibold mb-3" style={{ color: "#C6A15B" }}>{label}</div>
      <div className="flex gap-2 mb-3">
        <input value={draft} onChange={(e) => setDraft(e.target.value)} placeholder={placeholder} className="flex-1 rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} onKeyDown={(e) => e.key === "Enter" && add()} />
        <button onClick={add} className="px-3 rounded-xl" style={{ background: "#1F6B45" }}><Plus size={16} color="#F3EEDF" /></button>
      </div>
      <div className="space-y-2">
        {items.map((it, i) => (
          <div key={i} className="flex items-start justify-between gap-2 py-2 px-3 rounded-xl" style={{ background: "#0F1913" }}>
            <span className="text-xs leading-6" style={{ color: "#B7C4BB" }}>{it}</span>
            <button onClick={() => remove(i)} className="shrink-0"><Trash2 size={14} color="#E3866A" /></button>
          </div>
        ))}
      </div>
    </Card>
  );
}

function AdhkarEditor({ items, onSave }) {
  const [text, setText] = useState(""); const [repeat, setRepeat] = useState("");
  const add = () => { if (!text.trim()) return; onSave([...items, { text: text.trim(), repeat: repeat.trim() || "مرة واحدة" }]); setText(""); setRepeat(""); };
  const remove = (i) => onSave(items.filter((_, idx) => idx !== i));
  return (
    <Card>
      <div className="text-xs font-semibold mb-3" style={{ color: "#C6A15B" }}>الأذكار اليومية</div>
      <div className="space-y-2 mb-3">
        <input value={text} onChange={(e) => setText(e.target.value)} placeholder="نص الذكر" className="w-full rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
        <div className="flex gap-2">
          <input value={repeat} onChange={(e) => setRepeat(e.target.value)} placeholder="عدد المرات (مثال: سبع مرات)" className="flex-1 rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <button onClick={add} className="px-3 rounded-xl" style={{ background: "#1F6B45" }}><Plus size={16} color="#F3EEDF" /></button>
        </div>
      </div>
      <div className="space-y-2">
        {items.map((it, i) => (
          <div key={i} className="flex items-center justify-between gap-2 py-2 px-3 rounded-xl" style={{ background: "#0F1913" }}>
            <span className="text-xs" style={{ fontFamily: "'Cairo', sans-serif", fontWeight: 800, color: "#F3EEDF" }}>{it.text} <span className="text-[10px]" style={{ color: "#6E8377" }}>({it.repeat})</span></span>
            <button onClick={() => remove(i)} className="shrink-0"><Trash2 size={14} color="#E3866A" /></button>
          </div>
        ))}
      </div>
    </Card>
  );
}

function OccasionsEditor({ items, onSave }) {
  const [m, setM] = useState(HIJRI_MONTHS[0]); const [d, setD] = useState(""); const [t, setT] = useState("");
  const add = () => { if (!d || !t.trim()) return; onSave([...items, { m, d: Number(d), t: t.trim() }]); setD(""); setT(""); };
  const remove = (i) => onSave(items.filter((_, idx) => idx !== i));
  return (
    <Card>
      <div className="text-xs font-semibold mb-3" style={{ color: "#C6A15B" }}>مناسبات السنة الهجرية</div>
      <div className="space-y-2 mb-3">
        <div className="flex gap-2">
          <select value={m} onChange={(e) => setM(e.target.value)} className="flex-1 rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }}>
            {HIJRI_MONTHS.map((month) => <option key={month} value={month}>{month}</option>)}
          </select>
          <input value={d} onChange={(e) => setD(e.target.value)} type="number" placeholder="اليوم" className="w-20 rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
        </div>
        <div className="flex gap-2">
          <input value={t} onChange={(e) => setT(e.target.value)} placeholder="وصف المناسبة" className="flex-1 rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <button onClick={add} className="px-3 rounded-xl" style={{ background: "#1F6B45" }}><Plus size={16} color="#F3EEDF" /></button>
        </div>
      </div>
      <div className="space-y-2 max-h-80 overflow-y-auto">
        {items.map((o, i) => (
          <div key={i} className="flex items-center justify-between gap-2 py-2 px-3 rounded-xl" style={{ background: "#0F1913" }}>
            <span className="text-xs" style={{ color: "#B7C4BB" }}><b style={{ color: "#E3C078" }}>{o.d} {o.m}</b> — {o.t}</span>
            <button onClick={() => remove(i)} className="shrink-0"><Trash2 size={14} color="#E3866A" /></button>
          </div>
        ))}
      </div>
    </Card>
  );
}

function JsonEditor({ label, hint, value, onSave }) {
  const [text, setText] = useState(() => JSON.stringify(value, null, 2));
  const [error, setError] = useState("");
  const [saved, setSaved] = useState(false);
  const save = () => {
    try {
      const parsed = JSON.parse(text);
      onSave(parsed);
      setError(""); setSaved(true);
    } catch (e) {
      setError("صيغة JSON غير صحيحة — تأكد من الأقواس والفواصل. " + e.message);
    }
  };
  return (
    <Card>
      <div className="text-xs font-semibold mb-1" style={{ color: "#C6A15B" }}>{label}</div>
      {hint && <p className="text-[11px] mb-2" style={{ color: "#6E8377" }}>{hint}</p>}
      <textarea value={text} onChange={(e) => { setText(e.target.value); setSaved(false); }} dir="ltr" className="w-full h-64 rounded-xl px-3 py-2 text-[11px] outline-none resize-y font-mono" style={{ background: "#0F1913", border: "1px solid " + (error ? "#A6402F" : "#24382C"), color: "#F3EEDF" }} />
      <div className="flex items-center gap-2 mt-2">
        <button onClick={save} className="px-4 py-2 rounded-xl text-sm" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}>حفظ</button>
        {saved && <span className="text-[11px]" style={{ color: "#8FD6A8" }}>تم الحفظ ✓</span>}
      </div>
      {error && <p className="text-[11px] mt-2 leading-5" style={{ color: "#E3866A" }}>{error}</p>}
    </Card>
  );
}

function MafatihEditor({ mafatih, extras, onSave }) {
  const [babId, setBabId] = useState(mafatih[0] ? mafatih[0].id : "");
  const [title, setTitle] = useState("");
  const [source, setSource] = useState("");
  const [body, setBody] = useState("");
  const [saved, setSaved] = useState(false);

  const currentExtras = extras[babId] || [];

  const addSection = () => {
    if (!title.trim() || !body.trim()) return;
    onSave(babId, [...currentExtras, { title: title.trim(), source: source.trim(), body: body.trim() }]);
    setTitle(""); setSource(""); setBody("");
    setSaved(true); setTimeout(() => setSaved(false), 2500);
  };

  const removeSection = (idx) => {
    onSave(babId, currentExtras.filter((_, i) => i !== idx));
  };

  const currentBab = mafatih.find((b) => b.id === babId);

  return (
    <div className="space-y-3">
      <div className="rounded-xl p-3 text-[11px] leading-6" style={{ background: "#17261E", color: "#8FA396", border: "1px solid #24382C" }}>
        كتاب مفاتيح الجنان الأساسي مُضمّن بالكامل في التطبيق. هنا يمكنك إضافة أقسام إضافية فقط (تظهر بعد أقسام الكتاب الأصلية)، دون المساس بالنص الأصلي.
      </div>
      <Card>
        <div className="text-xs font-semibold mb-2" style={{ color: "#C6A15B" }}>اختر الباب</div>
        <select value={babId} onChange={(e) => setBabId(e.target.value)} className="w-full rounded-xl px-3 py-2 text-sm outline-none mb-3" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }}>
          {mafatih.map((b) => <option key={b.id} value={b.id}>{b.bab} — {b.title}</option>)}
        </select>

        <div className="space-y-2">
          <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="عنوان القسم (مثال: دعاء خاص)" className="w-full rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <input value={source} onChange={(e) => setSource(e.target.value)} placeholder="المصدر (اختياري)" className="w-full rounded-xl px-3 py-2 text-sm outline-none" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <textarea value={body} onChange={(e) => setBody(e.target.value)} placeholder="الصق نص القسم كاملاً هنا..." className="w-full h-40 rounded-xl px-3 py-2 text-sm outline-none resize-y" style={{ background: "#0F1913", border: "1px solid #24382C", color: "#F3EEDF" }} />
          <button onClick={addSection} className="w-full py-2.5 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}><Plus size={15} /> إضافة القسم</button>
          {saved && <p className="text-[11px] text-center" style={{ color: "#8FD6A8" }}>تمت الإضافة ✓</p>}
        </div>
      </Card>

      {currentBab && (
        <Card>
          <div className="text-xs font-semibold mb-2" style={{ color: "#C6A15B" }}>
            {currentBab.bab}: {currentBab.sections.length} قسم (منها {currentExtras.length} إضافة يمكن حذفها)
          </div>
          {currentExtras.length === 0 ? (
            <p className="text-[11px]" style={{ color: "#5C6B60" }}>لا توجد إضافات على هذا الباب. أقسام الكتاب الأصلية محمية ولا تظهر هنا للحذف.</p>
          ) : (
            <div className="space-y-1.5">
              {currentExtras.map((s, i) => (
                <div key={i} className="flex items-center justify-between gap-2 py-2 px-3 rounded-xl" style={{ background: "#0F1913" }}>
                  <span className="text-xs truncate" style={{ color: "#F3EEDF" }}>{s.title}</span>
                  <button onClick={() => removeSection(i)} className="shrink-0"><Trash2 size={13} color="#E3866A" /></button>
                </div>
              ))}
            </div>
          )}
        </Card>
      )}
    </div>
  );
}

function ContentManager({ content }) {
  const [tab, setTab] = useState("quick");
  const tabs = [
    { id: "quick", label: "سريع" },
    { id: "mafatih", label: "مفاتيح الجنان" },
    { id: "occasions", label: "المناسبات" },
    { id: "tips", label: "نصائح المفقودين" },
    { id: "adhkar", label: "الأذكار" },
    { id: "ziyarat", label: "زيارات الأسبوع" },
    { id: "major", label: "الزيارات الكبرى" },
    { id: "quran", label: "القرآن" },
  ];
  return (
    <div className="space-y-4">
      <div className="flex gap-2 overflow-x-auto pb-1">
        {tabs.map((t) => (
          <button key={t.id} onClick={() => setTab(t.id)} className="px-3.5 py-2 rounded-xl text-xs whitespace-nowrap" style={{ background: tab === t.id ? "linear-gradient(135deg,#1F6B45,#0F3D28)" : "transparent", border: "1px solid " + (tab === t.id ? "#C6A15B" : "#24382C"), color: tab === t.id ? "#F3EEDF" : "#8FA396" }}>{t.label}</button>
        ))}
      </div>

      {tab === "quick" && (
        <div className="space-y-3">
          <TextFieldEditor label="الاقتباس اليومي (الصفحة الرئيسية)" value={content.quote} onSave={content.saveQuote} multiline />
          <TextFieldEditor label="حدث في مثل هذا اليوم" value={content.todayEvent} onSave={content.saveTodayEvent} multiline />
        </div>
      )}
      {tab === "mafatih" && <MafatihEditor mafatih={content.mafatih} extras={content.mafatihExtras} onSave={content.saveMafatihExtras} />}
      {tab === "occasions" && <OccasionsEditor items={content.occasions} onSave={content.saveOccasions} />}
      {tab === "tips" && (
        <div className="space-y-3">
          <ListEditor label="نصائح للأطفال" items={content.kidsTips} onSave={content.saveKidsTips} placeholder="أضف نصيحة جديدة..." />
          <ListEditor label="نصائح للعائلة" items={content.familyTips} onSave={content.saveFamilyTips} placeholder="أضف نصيحة جديدة..." />
        </div>
      )}
      {tab === "adhkar" && <AdhkarEditor items={content.adhkar} onSave={content.saveAdhkar} />}
      {tab === "ziyarat" && <JsonEditor label="زيارات وأدعية أيام الأسبوع" hint="مصفوفة JSON — كل عنصر يمثل يوماً وفيه: day, who, source, dua, text, text2 (اختياري)." value={content.weekdayZiyarat} onSave={content.saveWeekdayZiyarat} />}
      {tab === "major" && <JsonEditor label="الزيارات والأدعية الكبرى" hint="مصفوفة JSON — كل عنصر فيه: t (العنوان), source, d (وصف مختصر), text (النص الكامل)، أو pending:true إذا لسه ناقص." value={content.majorTexts} onSave={content.saveMajorTexts} />}
      {tab === "quran" && <JsonEditor label="قائمة سور القرآن الكريم" hint="مصفوفة JSON — كل عنصر فيه: n (رقم السورة), name (الاسم), verses (عدد الآيات)." value={content.surahs} onSave={content.saveSurahs} />}
    </div>
  );
}

function DashboardView({ isAdmin, logoutAdmin, posts, setPosts, content }) {
  const [section, setSection] = useState("overview");
  const [counts, setCounts] = useState({ wallpapers: 0, books: 0 });
  const [recentWallpapers, setRecentWallpapers] = useState([]);
  const [recentBooks, setRecentBooks] = useState([]);
  const [now, setNow] = useState(new Date());

  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(id);
  }, []);

  useEffect(() => {
    (async () => {
      try {
        const wArr = await storage.getCollection("hayaa_wallpapers_v2");
        const bArr = await storage.getCollection("hayaa_library_v2");
        setCounts({ wallpapers: wArr.length, books: bArr.length });
        setRecentWallpapers(wArr.slice(0, 3));
        setRecentBooks(bArr.slice(0, 3));
      } catch (e) {}
    })();
  }, [section]);

  if (!isAdmin) {
    return (
      <div className="px-4 pb-10 pt-2 space-y-5">
        <SectionTitle eyebrow="خاص بإدارة الهيئة" title="لوحة التحكم" icon={LayoutDashboard} />
        <Card className="flex flex-col items-center text-center gap-3 !py-8">
          <div className="w-14 h-14 rounded-full flex items-center justify-center" style={{ background: "#1F6B4533" }}><KeyRound size={22} color="#E3C078" /></div>
          <p className="text-sm" style={{ color: "#B7C4BB" }}>هذه اللوحة خاصة بإدارة الهيئة — أدخل رمز الدخول للمتابعة.</p>
        </Card>
        <AdminGate />
      </div>
    );
  }

  const stats = [
    { label: "منشورات", value: posts.length, icon: Megaphone, color: "#8FD6A8" },
    { label: "خلفيات", value: counts.wallpapers, icon: ImageIcon, color: "#E3C078" },
    { label: "كتب PDF", value: counts.books, icon: Library, color: "#93B7E8" },
  ];

  const sections = [
    { id: "overview", label: "نظرة عامة", icon: BarChart3 },
    { id: "posts", label: "المنشورات", icon: Megaphone },
    { id: "content", label: "المحتوى الديني والعام", icon: FileText },
    { id: "media", label: "الخلفيات", icon: ImageIcon },
    { id: "library", label: "المكتبة", icon: Library },
  ];

  const greeting = now.getHours() < 12 ? "صباح الخير" : now.getHours() < 18 ? "مساء النور" : "مساء الخير";

  return (
    <div className="px-4 pb-10 pt-2 space-y-5">
      {/* رأس اللوحة */}
      <div className="relative rounded-[24px] overflow-hidden p-5 fade-up" style={{ background: "linear-gradient(150deg,#12281C,#080F0B 80%)", border: "1px solid #1C2B22" }}>
        <ShrineMark size={220} className="absolute -left-12 -top-10" />
        <div className="relative z-10 flex items-center justify-between">
          <div>
            <div className="text-[11px] tracking-widest" style={{ color: "#8FA396" }}>{greeting}</div>
            <div className="text-lg mt-0.5" style={{ fontFamily: "'Cairo', sans-serif", fontWeight: 800, color: "#F3EEDF" }}>لوحة تحكم الهيئة</div>
            <div className="text-[11px] mt-1 flex items-center gap-1.5" style={{ color: "#6E8377" }}><KeyRound size={11} /> {ADMIN_EMAIL}</div>
          </div>
          <button onClick={logoutAdmin} className="flex items-center gap-1.5 text-xs px-3 py-2.5 rounded-xl shrink-0" style={{ background: "#A6402F22", border: "1px solid #A6402F55", color: "#E3866A" }}><LogOut size={13} /> خروج</button>
        </div>
      </div>

      {/* شريط الأقسام */}
      <div className="flex gap-2 overflow-x-auto pb-1">
        {sections.map((s) => (
          <button key={s.id} onClick={() => setSection(s.id)} className="px-4 py-2.5 rounded-xl text-sm flex items-center gap-1.5 whitespace-nowrap" style={{ background: section === s.id ? "linear-gradient(135deg,#1F6B45,#0F3D28)" : "#101B15", border: "1px solid " + (section === s.id ? "#C6A15B" : "#1C2B22"), color: section === s.id ? "#F3EEDF" : "#8FA396", fontWeight: section === s.id ? 700 : 500 }}>
            <s.icon size={14} /> {s.label}
          </button>
        ))}
      </div>

      {section === "overview" && (
        <div className="space-y-4">
          {/* إحصائيات */}
          <div className="grid grid-cols-3 gap-3">
            {stats.map((s) => (
              <Card key={s.label} className="!p-4 text-center">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center mx-auto mb-2" style={{ background: s.color + "22" }}>
                  <s.icon size={16} color={s.color} />
                </div>
                <div style={{ fontFamily: "'Cairo', sans-serif", fontWeight: 800, fontSize: 22, color: "#F3EEDF" }}>{s.value}</div>
                <div className="text-[10px] mt-1" style={{ color: "#8FA396" }}>{s.label}</div>
              </Card>
            ))}
          </div>

          {/* الوصول السريع */}
          <Card>
            <div className="text-sm font-semibold mb-3" style={{ color: "#F3EEDF" }}>الوصول السريع</div>
            <div className="grid grid-cols-2 gap-2">
              {sections.filter((s) => s.id !== "overview").map((s) => (
                <button key={s.id} onClick={() => setSection(s.id)} className="flex flex-col items-start gap-2 py-3 px-3 rounded-xl" style={{ background: "#0F1913", border: "1px solid #1C2B22" }}>
                  <s.icon size={16} color="#C6A15B" />
                  <span className="text-xs" style={{ color: "#F3EEDF" }}>{s.label}</span>
                </button>
              ))}
            </div>
          </Card>

          {/* آخر النشاط */}
          {posts.length > 0 && (
            <Card>
              <div className="flex items-center justify-between mb-3">
                <div className="text-sm font-semibold" style={{ color: "#F3EEDF" }}>آخر المنشورات</div>
                <button onClick={() => setSection("posts")} className="text-[11px]" style={{ color: "#C6A15B" }}>عرض الكل</button>
              </div>
              <div className="space-y-2">
                {posts.slice(0, 3).map((p) => (
                  <div key={p.id} className="flex items-center justify-between py-2 px-3 rounded-xl" style={{ background: "#0F1913" }}>
                    <span className="text-xs truncate" style={{ color: "#F3EEDF" }}>{p.title}</span>
                    <span className="text-[10px] shrink-0 mr-2" style={{ color: "#6E8377" }}>{p.date}</span>
                  </div>
                ))}
              </div>
            </Card>
          )}

          {(recentWallpapers.length > 0 || recentBooks.length > 0) && (
            <Card>
              <div className="text-sm font-semibold mb-3" style={{ color: "#F3EEDF" }}>آخر الملفات المرفوعة</div>
              <div className="grid grid-cols-3 gap-2 mb-2">
                {recentWallpapers.map((w) => (
                  <div key={w._key} className="aspect-square rounded-xl overflow-hidden"><img src={w.src} alt="" className="w-full h-full object-cover" /></div>
                ))}
              </div>
              {recentBooks.map((b) => (
                <div key={b._key} className="flex items-center gap-2 py-2 px-3 rounded-xl mb-1" style={{ background: "#0F1913" }}>
                  <FileText size={13} color="#93B7E8" />
                  <span className="text-xs truncate" style={{ color: "#F3EEDF" }}>{b.name}</span>
                </div>
              ))}
            </Card>
          )}

          <div className="rounded-xl p-4 text-xs leading-6 flex items-start gap-2" style={{ background: "#17261E", color: "#8FA396", border: "1px solid #24382C" }}>
            <Eye size={14} className="mt-0.5 shrink-0" />
            <span>كل ما تنشره أو تعدّله هنا يظهر مباشرة لجميع زوار الموقع فور الحفظ.</span>
          </div>
        </div>
      )}

      {section === "posts" && <div className="-mx-4"><PostsView posts={posts} setPosts={setPosts} isAdmin={isAdmin} /></div>}
      {section === "content" && <ContentManager content={content} />}
      {section === "media" && <div className="-mx-4"><MediaView isAdmin={isAdmin} /></div>}
      {section === "library" && <div className="-mx-4"><LibraryView isAdmin={isAdmin} /></div>}
    </div>
  );
}

function SettingsView({ goTo }) {
  const [open, setOpen] = useState(null);
  const [installEvt, setInstallEvt] = useState(null);
  const [shared, setShared] = useState(false);

  useEffect(() => {
    const handler = (e) => { e.preventDefault(); setInstallEvt(e); };
    window.addEventListener("beforeinstallprompt", handler);
    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const installApp = async () => {
    if (!installEvt) return;
    installEvt.prompt();
    await installEvt.userChoice;
    setInstallEvt(null);
  };

  const shareApp = async () => {
    const data = { title: "هيئة الشيخ أحمد الوائلي", text: "تطبيق ثقافي توعوي — القرآن، الأدعية والزيارات، محاضرات الشيخ الوائلي.", url: "https://hayiaa-alwaeli-app.onrender.com" };
    try {
      if (navigator.share) await navigator.share(data);
      else { await navigator.clipboard.writeText(data.url); setShared(true); setTimeout(() => setShared(false), 2500); }
    } catch (e) {}
  };

  const toggle = (id) => setOpen(open === id ? null : id);

  const Row = ({ id, icon: Icon, label, children }) => (
    <Card onClick={() => toggle(id)} style={{ cursor: "pointer" }}>
      <div className="flex items-center justify-between">
        <span className="text-sm flex items-center gap-2.5" style={{ color: "#F3EEDF" }}><Icon size={16} color="#C6A15B" /> {label}</span>
        <ChevronDown size={16} color="#8FA396" style={{ transform: open === id ? "rotate(180deg)" : "none", transition: "transform .2s" }} />
      </div>
      {open === id && <div className="mt-3 pt-3 text-xs leading-7" style={{ borderTop: "1px solid #24382C", color: "#B7C4BB" }}>{children}</div>}
    </Card>
  );

  return (
    <div className="px-4 pb-10 pt-2 space-y-4">
      <SectionTitle eyebrow="تخصيص" title="الإعدادات" icon={Settings} />

      {/* تثبيت التطبيق */}
      {installEvt && (
        <button onClick={installApp} className="w-full py-3 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#C6A15B", color: "#0A1310", fontWeight: 700 }}>
          <Download size={16} /> تثبيت التطبيق على جهازك
        </button>
      )}

      {/* مشاركة التطبيق */}
      <button onClick={shareApp} className="w-full py-3 rounded-xl text-sm flex items-center justify-center gap-2" style={{ background: "#101B15", border: "1px solid #1C2B22", color: "#E3C078", fontWeight: 700 }}>
        <Share2 size={16} /> {shared ? "تم نسخ الرابط ✓" : "مشاركة التطبيق"}
      </button>

      <Row id="about" icon={Info} label="عن الهيئة">
        هيئة الشيخ أحمد الوائلي — هيئة ثقافية توعوية تُعنى بنشر فكر وإرث الخطيب الكبير الشيخ أحمد الوائلي رحمه الله، عبر المحاضرات والمنبر الحسيني والمحتوى الديني الهادف.
        <div className="flex gap-3 mt-3">
          <a href={SOCIAL.instagram} target="_blank" rel="noreferrer" className="w-9 h-9 rounded-full flex items-center justify-center" style={{ background: "#17261E" }}><Instagram size={16} color="#E3C078" /></a>
          <a href={SOCIAL.facebook} target="_blank" rel="noreferrer" className="w-9 h-9 rounded-full flex items-center justify-center" style={{ background: "#17261E" }}><Facebook size={16} color="#E3C078" /></a>
          <a href={SOCIAL.tiktok} target="_blank" rel="noreferrer" className="w-9 h-9 rounded-full flex items-center justify-center" style={{ background: "#17261E" }}><TikTokIcon size={15} /></a>
        </div>
      </Row>

      <Row id="prayer" icon={Moon} label="طريقة حساب المواقيت">
        تُحسب مواقيت الصلاة تلقائياً حسب موقعك الجغرافي، وفق الطريقة الجعفرية (الشيعة الإثنا عشرية) المعتمدة، مع احتساب منتصف الليل الشرعي من الغروب إلى الفجر. لتغيير دقة الموقع، فعّل إذن الموقع من إعدادات المتصفح.
      </Row>

      <Row id="madhab" icon={BookMarked} label="المذهب الفقهي">
        التطبيق مُعدّ وفق مذهب أهل البيت عليهم السلام (الجعفري الإثنا عشري)، ويشمل الأدعية والزيارات ومواقيت الصلاة وفق هذا المذهب.
      </Row>

      <Row id="notif" icon={Bell} label="الإشعارات">
        لتلقّي تنبيهات مواقيت الصلاة والمناسبات، تأكد من السماح بالإشعارات لهذا الموقع من إعدادات متصفحك. (خدمة الإشعارات التلقائية قيد التطوير وستتوفر في تحديث قادم.)
      </Row>

      <Row id="privacy" icon={ShieldAlert} label="الخصوصية">
        لا يجمع التطبيق بياناتك الشخصية ولا يشاركها. الموقع والحسّاسات تُستخدم محلياً على جهازك فقط لحساب المواقيت والقبلة وعدد الخطى.
      </Row>

      <button onClick={() => goTo("dashboard")} className="w-full text-center text-[11px] pt-4" style={{ color: "#3E4E45" }}>دخول إدارة الهيئة</button>
    </div>
  );
}

/* ------------------------------------- التطبيق ------------------------------------- */

export default function App() {
  const [showSplash, setShowSplash] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [active, setActive] = useState("home");
  const [dateMode, setDateMode] = useState("hijri");
  const [posts, setPosts] = useState([]);
  const [authUser, setAuthUser] = useState(undefined); // undefined = لسه ما تحقق، null = زائر غير مسجل

  // كل قسم محتوى قابل للتعديل من لوحة التحكم — مزامن مباشرة مع Firebase
  const [occasions, saveOccasions] = useSyncedContent("hayaa_occasions", DEFAULT_OCCASIONS);
  const [weekdayZiyarat, saveWeekdayZiyarat] = useSyncedContent("hayaa_weekday_ziyarat", DEFAULT_WEEKDAY_ZIYARAT);
  const [majorTexts, saveMajorTexts] = useSyncedContent("hayaa_major_texts", DEFAULT_MAJOR_TEXTS);
  const [adhkar, saveAdhkar] = useSyncedContent("hayaa_adhkar", DEFAULT_ADHKAR);
  const [surahs, saveSurahs] = useSyncedContent("hayaa_surahs", DEFAULT_SURAHS);
  const [mafatih, mafatihExtras, saveMafatihExtras] = useMafatih();
  const [kidsTips, saveKidsTips] = useSyncedContent("hayaa_kids_tips", DEFAULT_KIDS_TIPS);
  const [familyTips, saveFamilyTips] = useSyncedContent("hayaa_family_tips", DEFAULT_FAMILY_TIPS);
  const [quote, saveQuote] = useSyncedContent("hayaa_quote", DEFAULT_QUOTE);
  const [todayEvent, saveTodayEvent] = useSyncedContent("hayaa_today_event", DEFAULT_EVENT);

  const prayerData = usePrayerData();

  useEffect(() => {
    (async () => {
      try { const res = await storage.get("hayaa_posts"); if (res && res.value) setPosts(JSON.parse(res.value)); } catch (e) {}
    })();
  }, []);

  // يتابع حالة تسجيل الدخول — أي زائر (بجوجل أو كزائر) يصير authUser،
  // لكن isAdmin ما تصير true إلا إذا كان الإيميل يطابق حساب الأدمن بالتحديد.
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => setAuthUser(user));
    return () => unsubscribe();
  }, []);
  const isAdmin = !!(authUser && authUser.email === ADMIN_EMAIL);

  const gregorian = new Date().toLocaleDateString("ar-IQ", { weekday: "long", year: "numeric", month: "long", day: "numeric" });
  const hijri = (() => {
    try {
      return new Intl.DateTimeFormat("ar-SA-u-ca-islamic-umalqura", { day: "numeric", month: "long", year: "numeric" }).format(new Date()) + " هـ";
    } catch (e) {
      return new Intl.DateTimeFormat("ar-SA-u-ca-islamic", { day: "numeric", month: "long", year: "numeric" }).format(new Date()) + " هـ";
    }
  })();

  const content = {
    occasions, saveOccasions,
    weekdayZiyarat, saveWeekdayZiyarat,
    majorTexts, saveMajorTexts,
    adhkar, saveAdhkar,
    surahs, saveSurahs,
    mafatih, mafatihExtras, saveMafatihExtras,
    kidsTips, saveKidsTips,
    familyTips, saveFamilyTips,
    quote, saveQuote,
    todayEvent, saveTodayEvent,
  };

  const views = {
    home: <HomeView gregorian={gregorian} hijri={hijri} posts={posts} goTo={setActive} quote={quote} todayEvent={todayEvent} weekdayZiyarat={weekdayZiyarat} adhkar={adhkar} prayerData={prayerData} />,
    posts: <PostsView posts={posts} setPosts={setPosts} isAdmin={isAdmin} />,
    calendar: <CalendarView occasions={occasions} />,
    quran: <QuranView surahs={surahs} />,
    mafatih: <MafatihView mafatih={mafatih} />,
    supplications: <SupplicationsView weekdayZiyarat={weekdayZiyarat} majorTexts={majorTexts} adhkar={adhkar} goTo={setActive} />,
    lectures: <LecturesView />,
    rosary: <RosaryView />,
    prayers: <PrayersView prayerData={prayerData} />,
    qibla: <QiblaView prayerData={prayerData} />,
    gps: <GpsView kidsTips={kidsTips} familyTips={familyTips} />,
    notebook: <NotebookView />,
    steps: <StepsView />,
    media: <MediaView isAdmin={isAdmin} />,
    library: <LibraryView isAdmin={isAdmin} />,
    settings: <SettingsView goTo={setActive} />,
    dashboard: <DashboardView isAdmin={isAdmin} logoutAdmin={() => signOut(auth)} posts={posts} setPosts={setPosts} content={content} />,
  };

  return (
    <div dir="rtl" className="min-h-screen w-full" style={{ background: "#0A1310", fontFamily: "'Cairo', sans-serif", fontWeight: 600, WebkitFontSmoothing: "antialiased", textRendering: "optimizeLegibility" }}>
      <style>{FONTS}</style>
      {showSplash && <Splash onDone={() => setShowSplash(false)} />}
      {!showSplash && authUser === null && <WelcomeGate />}
      <div className="max-w-md mx-auto min-h-screen relative" style={{ boxShadow: "0 0 60px #00000066" }}>
        <Header onMenu={() => setSidebarOpen(true)} dateMode={dateMode} setDateMode={setDateMode} gregorian={gregorian} hijri={hijri} />
        <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} active={active} setActive={setActive} />
        {views[active]}
        <div className="sticky bottom-0 left-0 right-0 px-4 pb-3">
          <div className="flex items-center justify-around py-2.5 rounded-2xl" style={{ background: "rgba(13,23,18,0.92)", backdropFilter: "blur(14px)", border: "1px solid #1C2B22" }}>
            {[{ id: "home", icon: Sparkles, label: "الرئيسية" }, { id: "posts", icon: Megaphone, label: "المنشورات" }, { id: "gps", icon: MapPin, label: "المفقودين" }, { id: "rosary", icon: RotateCcw, label: "المسبحة" }, { id: "calendar", icon: CalendarDays, label: "التقويم" }].map((n) => {
              const Icon = n.icon; const isActive = active === n.id;
              return (<button key={n.id} onClick={() => setActive(n.id)} className="flex flex-col items-center gap-1 px-2"><Icon size={18} color={isActive ? "#E3C078" : "#5C6B60"} /><span className="text-[10px]" style={{ color: isActive ? "#E3C078" : "#5C6B60" }}>{n.label}</span></button>);
            })}
          </div>
        </div>
      </div>
    </div>
  );
}
